import { TestConfiguration, PromiseUtils } from '../src/main';
import * as path from 'path';

/**
 * These are the codes that the skill emits depending
 * on how its logic branched
 */
const TestCodes = {
	OOBE_CLOSE: 'OOBE_CLOSE',
	SOME_DUDE_LATE: 'SOME_DUDE_LATE',
	LOW_PROB: 'LATE_LOW_PROB',
	DEFAULT: 'DEFAULT',
};

/**
 * Example skill showing how we can both automatically test skill branching logic with unit tests
 * and how we can allow QA to test various logic branches through a test testConfig json file
 */
class TestSkill extends BeSkill {

	public testConfig = new TestConfiguration('TestSkill');

	// These should be implemented and individually tested
	private _determineTime() { /* Implement */ }
	private _determineUserName() { /* Implement */ }
	private _determineDaysSinceOOBE() { /* Implement */ }

	/**
	 * Called by BE one time when the environment is loaded and ready
	 * @param {function} done
	 */
	postInit(done) {
		// Load potential test configuration options from disk
		// This is where QA can override some options to test particular skill logic branches
		this.testConfig.init(path.join(this.root, 'testConfig.json'))
			.then(done).catch(done);
	}

	/**
	 * Called by BE when the skill opens
	 * @param {object} options
	 */
	open(options) {
		this.skillLogic(options)
			.then( code => {
				// Emit the test code that our skill tests might be waiting for
				this.testConfig.emit(code);
				this.exit();
			});
	}

	/**
	 * This method is sort of like a "poor dev's flow"
	 */
	private async skillLogic(options): Promise<string> {
		// We get the days since oobe
		const daysSinceOOBE = await this.testConfig.getNumberFromTestConfig(
			'daysSinceOOBE', this._determineDaysSinceOOBE.bind(this));

		// If oobe happened recently
		if (daysSinceOOBE < 3) {
			// Do some skill specific stuff
			return TestCodes.OOBE_CLOSE;
		}

		// We grab some control options
		const after3PM = await this.testConfig.getBooleanFromTestConfig(
			'after3PM', this._determineTime.bind(this));
		const userName = await this.testConfig.getStringFromTestConfig(
			'userName', this._determineUserName.bind(this));

		// If user is Jonathan and its late
		if (userName === 'Jonathan' && after3PM) {
			// Do some skill specific stuff
			return TestCodes.SOME_DUDE_LATE;
		}

		// We grab some control options
		const randomA = await this.testConfig.getNumberFromTestConfig(
			'randomA', this._determineDaysSinceOOBE.bind(this));

		// Otherwise, with low probability do...
		if (randomA < 0.1) {
			// Do some skill specific stuff
			return TestCodes.LOW_PROB;
		}
		// With higher probability do...
		else {
			// Do some skill specific stuff
			return TestCodes.DEFAULT;
		}
	}
}

// -----------------------------------------
// Start of new file containing mocha tests
// -----------------------------------------

/*
 * Generalized skill branch test creator
 */
async function createTest(testData: any, expectedEvent: string): Promise<void> {
	const skill = new TestSkill();
	await PromiseUtils.promisify( h => skill.postInit(h) );
	skill.testConfig.setOverridingTestConfig(testData);

	// Open up the skill and wait for the expected event (next tick to ensure event doesn't pass us by)
	process.nextTick( () => skill.open({}) );
	await skill.testConfig.waitForEvent(expectedEvent);
}

/*
 * Test cases
 */
it('Should not do much soon after OOBE', () => {
	return createTest({
		daysSinceOOBE: 1
	}, TestCodes.OOBE_CLOSE);
});

it('Should do some stuff OOBE long gone and Jonathan is late', () => {
	return createTest({
		daysSinceOOBE: 1000000,
		userName: 'Jonathan',
		after3PM: true
	}, TestCodes.SOME_DUDE_LATE);
});

it('Should do some stuff OOBE long gone and Jonathan is nowhere to be seen, 10% of the time', () => {
	return createTest({
		daysSinceOOBE: 1000000,
		userName: 'bla',
		randomA: 0
	}, TestCodes.LOW_PROB);
});

it('Should do some stuff OOBE long gone and Jonathan is nowhere to be seen, 90% of the time', () => {
	return createTest({
		daysSinceOOBE: 1000000,
		userName: 'bla',
		randomA: 1
	}, TestCodes.DEFAULT);
});

// These tests need to be written since none of the above tests actually verify
// that these methods work well (they bypass them with overriding options)
